<?php
namespace Database\Seeders; use App\Models\Card; use Illuminate\Database\Seeder;
class CardSeeder extends Seeder { public function run(): void { $events=['Miss the bus','Lose your keys','Crack your phone screen','Get caught in heavy rain','Forget an important birthday','Step on a toy','Receive a parking ticket','Delete an unsaved document','Get food poisoning','Miss a flight','Lose your wallet','Have a toothache','Get locked out','Internet stops working','Spill coffee on your laptop','Wake up late','Get a flat tire','Fail an exam','Have your card declined','Break your favorite mug']; for($i=1;$i<=100;$i++){Card::updateOrCreate(['title'=>$events[($i-1)%count($events)].' #'.$i],['score'=>round((($i*37)%1000)/10,1),'image'=>'0','deck'=>$i%5===0?'spicy':'normal']);} } }
